import { describe, expect, test } from '@a0n/gnosis/test';
import {
  marginalFoldWork,
  marginalFoldZeroIffHit,
} from './cache-observation-bridge';

describe('cache-observation-bridge (CacheObservation.lean mirror)', () => {
  test('marginal_fold_hit', () => {
    expect(marginalFoldWork({ kind: 'hit' })).toBe(0);
  });

  test('marginal_fold_cold', () => {
    expect(marginalFoldWork({ kind: 'cold_miss', work: { val: 7 } })).toBe(7);
  });

  test('marginal_fold_stale', () => {
    expect(marginalFoldWork({ kind: 'stale_miss', work: { val: 3 } })).toBe(3);
  });

  test('marginal_fold_zero_iff_hit', () => {
    expect(marginalFoldZeroIffHit({ kind: 'hit' })).toBe(true);
    expect(marginalFoldZeroIffHit({ kind: 'cold_miss', work: { val: 1 } })).toBe(
      true
    );
    expect(
      marginalFoldZeroIffHit({ kind: 'stale_miss', work: { val: 2 } })
    ).toBe(true);
  });
});
